class Solution:
    def change(self, total, denominations):
        dp = [float('inf')] * (total + 1)
        dp[0] = 0
        for coin in denominations:
            for i in range(coin, total + 1):
                dp[i] = min(dp[i], dp[i - coin] + 1)
        return dp[total] if dp[total] != float('inf') else -1

