class Solution {
    public:
        int change(int total, vector<int>& denominations) {
            if (total == 0)
                return 0;
            vector<int> dp(total + 1, INT_MAX);
            dp[0] = 0;
            for (int i = 1; i <= total; i++)
                for (int coin : denominations)
                    if (i >= coin)
                        dp[i] = min(dp[i], dp[i - coin] + 1);
            return dp[total] == INT_MAX ? -1 : dp[total];
        }
};

